export default function Sidebar({ activeView, setActiveView }) {
  return (
    <nav className="flex flex-col items-center w-[clamp(60px,4.5vw,80px)] min-w-[60px] bg-[#f3f2f1] border-r border-[#e0e0e0] pt-2 pb-2 select-none">
      {/* Top items */}
      <div className="flex flex-col items-center gap-1 flex-1">
        {sidebarItems.map((item) => {
          const isActive = (item.id === 'chat' && activeView === 'chat') || (item.id === 'copilot' && activeView === 'copilot')
          const isClickable = item.id === 'chat' || item.id === 'copilot'
          return (
            <button
              key={item.id}
              onClick={() => isClickable && setActiveView(item.id)}
              className={`
                relative flex flex-col items-center justify-center w-[clamp(48px,3.5vw,64px)] h-[clamp(44px,3.5vw,60px)] rounded-md
                transition-colors duration-100
                ${isActive
                  ? 'text-[#6264A7] font-semibold'
                  : 'text-[#616161] hover:text-[#242424] hover:bg-[#e8e8e8]'
                }
                ${isClickable ? 'cursor-pointer' : 'cursor-default'}
              `}
            >
              {isActive && (
                <div className="absolute left-0 top-[12px] bottom-[12px] w-[3px] bg-[#6264A7] rounded-r-full" />
              )}
              <span className="w-6 h-6 flex items-center justify-center">
                {item.icon}
              </span>
              <span className={`leading-none mt-[3px] text-[10px] ${isActive ? 'text-[#6264A7] font-semibold' : ''}`}>{item.label}</span>
              {item.badge && (
                <span className="absolute top-1 right-1 min-w-[16px] h-[16px] bg-[#C4314B] text-white text-[9px] font-bold rounded-full flex items-center justify-center px-1">
                  {item.badge}
                </span>
              )}
            </button>
          )
        })}
      </div>

      {/* Bottom items */}
      <div className="flex flex-col items-center gap-1">
        {bottomItems.map((item) => (
          <button
            key={item.id}
            className="relative flex flex-col items-center justify-center w-[clamp(48px,3.5vw,64px)] h-[clamp(44px,3.5vw,60px)] rounded-md text-[#616161] hover:text-[#242424] hover:bg-[#e8e8e8] transition-colors duration-100 cursor-default"
          >
            <span className="w-6 h-6 flex items-center justify-center">
              {item.icon}
            </span>
            {item.label && <span className="leading-none mt-[3px] text-[10px]">{item.label}</span>}
          </button>
        ))}
      </div>
    </nav>
  )
}
